from datetime import datetime, timedelta
from dataclasses import dataclass

@dataclass
class StatusPageCadenceTracker:
    incident_id: str
    severity: str                # "p0" | "p1" | "p2"
    current_state: str           # "investigating" | "identified" | "monitoring" | "resolved"
    last_update_at: datetime

    def interval_minutes(self) -> int:
        if self.current_state in ("monitoring", "resolved"):
            return 0             # no periodic updates required
        cadence = {
            ("p0", "investigating"): 15,
            ("p0", "identified"):    30,
            ("p1", "investigating"): 30,
            ("p1", "identified"):    30,
            ("p2", "investigating"): 60,
            ("p2", "identified"):    0,  # change-only for P2
        }
        return cadence.get((self.severity, self.current_state), 60)

    def next_update_due(self) -> datetime | None:
        mins = self.interval_minutes()
        if mins == 0:
            return None
        return self.last_update_at + timedelta(minutes=mins)

    def is_overdue(self) -> bool:
        due = self.next_update_due()
        if due is None:
            return False
        return datetime.utcnow() > due

    def reminder_message(self) -> str:
        due = self.next_update_due()
        if due is None:
            return ""
        overdue_by = datetime.utcnow() - due
        if overdue_by.total_seconds() > 0:
            return (
                f":warning: Status page update overdue by "
                f"{int(overdue_by.total_seconds() // 60)} min for INC-{self.incident_id}. "
                f"@comms-lead please post an update."
            )
        mins_left = int((due - datetime.utcnow()).total_seconds() // 60)
        return (
            f":clock3: Status page update due in {mins_left} min for "
            f"INC-{self.incident_id} ({self.current_state})."
        )
